sections.code_example:
def divide(a, b):
    try:
        result = a / b
        print("Result:", result)
    except ZeroDivisionError:
        print("Error: Cannot divide by zero!")
    except TypeError:
        print("Error: Both values must be numbers!")

divide(10, 2)
divide(10, 0)
divide(10, "two")

def parse_input(text):
    try:
        return int(text)
    except (ValueError, TypeError):
        print("Could not parse:", text)
        return 0

print(parse_input("42"))
print(parse_input("hello"))
print(parse_input(None))

try:
    x = int("oops")
except ValueError:
    print("Not a valid number")
except Exception as e:
    print("Unexpected error:", type(e).__name__, e)

exercises.solution:
def lookup(data, key):
    try:
        return int(data[key])
    except KeyError:
        print("Key not found")
        return None
    except ValueError:
        print("Not a number")
        return None

print(lookup({"score": "95"}, "score"))
lookup({"score": "abc"}, "score")
lookup({"score": "95"}, "name")

def safe_convert(value):
    try:
        return float(value)
    except (ValueError, TypeError):
        return 0.0

print(safe_convert("3.14"))
print(safe_convert("bad"))
print(safe_convert(None))
